import { heartbeat, isCancellation } from '@temporalio/activity';

const WORK_DURATION_MS = 60_000;
const HEARTBEAT_INTERVAL_MS = 500;

export async function doWork(): Promise<void> {
  const start = Date.now();

  while (Date.now() - start < WORK_DURATION_MS) {
    try {
      heartbeat({ progressMs: Date.now() - start });
    } catch (err) {
      if (isCancellation(err)) {
        throw err;
      }
      throw err;
    }

    await new Promise((resolve) => setTimeout(resolve, HEARTBEAT_INTERVAL_MS));
  }
}

export async function cleanup(): Promise<string> {
  return 'cleanup-done';
}

import {
  ActivityCancellationType,
  CancellationScope,
  isCancellation,
  proxyActivities,
} from '@temporalio/workflow';
import type * as activities from './activities';

const { doWork, cleanup } = proxyActivities<typeof activities>({
  startToCloseTimeout: '90s',
  heartbeatTimeout: '10s',
  cancellationType: ActivityCancellationType.TRY_CANCEL,
});

export async function CancellableWorkflow(): Promise<void> {
  try {
    await CancellationScope.cancellable(async () => {
      await doWork();
    });
  } catch (err) {
    if (isCancellation(err)) {
      await CancellationScope.nonCancellable(async () => cleanup());
      throw err;
    }
    throw err;
  }
}

import { NativeConnection, Worker } from '@temporalio/worker';
import { cleanup, doWork } from './activities';

const taskQueue = 'cancel-cleanup-ts';

export async function createWorker(): Promise<Worker> {
  const connection = await NativeConnection.connect({
    address: process.env.TEMPORAL_ADDRESS,
    apiKey: process.env.TEMPORAL_API_KEY,
    tls: true,
  });

  return Worker.create({
    connection,
    namespace: process.env.TEMPORAL_NAMESPACE,
    taskQueue,
    workflowsPath: require.resolve('./workflows'),
    activities: { doWork, cleanup },
  });
}

import { Client, Connection } from '@temporalio/client';
import { isCancellation } from '@temporalio/workflow';

const taskQueue = 'cancel-cleanup-ts';

export async function runClient(): Promise<void> {
  const connection = await Connection.connect({
    address: process.env.TEMPORAL_ADDRESS,
    apiKey: process.env.TEMPORAL_API_KEY,
    tls: true,
  });

  const client = new Client({
    connection,
    namespace: process.env.TEMPORAL_NAMESPACE,
  });

  const runId = process.env.ZEALT_RUN_ID ?? 'missing-run-id';
  const workflowId = `cancel-wf-${runId}`;

  const handle = await client.workflow.start('CancellableWorkflow', {
    taskQueue,
    workflowId,
  });

  await new Promise((resolve) => setTimeout(resolve, 3000));
  await handle.cancel();

  try {
    await handle.result();
  } catch (err) {
    if (isCancellation(err)) {
      console.log('cleanup-done observed');
      return;
    }
    throw err;
  }
}

import { createWorker } from './worker';
import { runClient } from './client';

async function main(): Promise<void> {
  const worker = await createWorker();
  const workerRun = worker.run();

  await new Promise((resolve) => setTimeout(resolve, 1500));

  try {
    await runClient();
  } finally {
    await worker.shutdown();
    await workerRun;
  }
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
